INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6f0ba476-moex-00062', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '所得稅法第4條之4規定之個人房屋、土地交易所得或損失之計算，關於稅率之規定，下列何者 錯誤？', '["中華民國境內居住之個人持有房屋、土地之期間超過十年者，稅率為百分之十", "非中華民國境內居住之個人持有房屋、土地之期間超過二年者，稅率為百分之三十五", "中華民國境內居住之個人因財政部公告之調職、非自願離職或其他非自願性因素，交易持有期 間在五年以下之房屋、土地者，稅率為百分之二十", "中華民國境內居住之個人提供土地、合法建築物、他項權利或資金，依都市危險及老舊建築物 加速重建條例參與重建，於興建房屋完成後取得之房屋及其坐落基地第一次移轉且其持有期間 在五年以下者，稅率為百分之二十"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00063', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '營利事業所得額之計算，以其本年度收入總額減除各項成本費用、損失及稅捐後之純益額為所得 額。下列敘述何者錯誤？', '["營利事業持有金融債券，應按債券持有期間，依債券之面值及利率計算利息收入。若於二付息 日間購入金融債券並於付息日前出售者，應以售價減除購進價格，並減除依債券之面值及利率 計算之利息收入，餘額為證券交易所得或損失", "凡遭受不可抗力之災害損失受有保險賠償部份，不得列為費用或損失", "各種稅法所規定之滯報金、怠報金、滯納金等及各項罰鍰，不得列為費用或損失", "公司、合作社及其他法人之營利事業，因投資於國內其他營利事業，所獲配之股利或盈餘，計 入當年度所得額課稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00064', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '關於所得稅法之稽徵程序，下列敘述何者錯誤？', '["未符合所得稅法第69條規定之營利事業，應於每年9月1日起至9月30日止，按其上年度結 算申報營利事業所得稅應納稅額之二分之一為暫繳稅額，自行向庫繳納，並依規定格式，填具 暫繳稅額申報書，檢附暫繳稅額繳款收據，一併向該管稽徵機關申報", "公司組織之營利事業，會計帳冊簿據完備，使用所得稅法第 77 條所稱藍色申報書或經會計師 查核簽證，並如期辦理暫繳申報者，得以當年度前6個月之營業收入總額，依所得稅法有關營 利事業所得稅之規定，試算其前半年之營利事業所得額，按當年度稅率，計算其暫繳稅額，不 適用所得稅法第67條第1項暫繳稅額之計算方式", "營利事業遇有解散、廢止、合併或轉讓情事時，應於截至解散、廢止、合併或轉讓之日止，辦 理當期決算，於60日內，依規定格式，向該管稽徵機關申報其營利事業所得額及應納稅額，並 於提出申報前自行繳納", "營利事業宣告破產者，應於法院公告債權申報期間截止10日前，向該管稽徵機關提出當期營利 事業所得稅決算申報；其未依限申報者，稽徵機關應即依查得之資料，核定其所得額及應納稅額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00065', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '關於特種貨物及勞務稅條例，下列敘述何者錯誤？', '["每件銷售價格或完稅價格達新臺幣五十萬元之家具，為特種貨物", "包括駕駛人座位在內，座位在九座以下之載人汽車，且每輛銷售價格或完稅價格達新臺幣二百 萬元，為特種貨物", "每次銷售價格達新臺幣五十萬元之入會權利，為特種勞務", "每艘船身全長達三十點四八公尺之遊艇，為特種貨物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00066', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依「加值型及非加值型營業稅法」關於「申報繳納」之規定，下列選項何者錯誤？', '["外國技藝表演業，在中華民國境內演出期間20日之營業稅，應於演出結束後15日內向演出地 主管稽徵機關報繳", "外國技藝表演業，須在加值型及非加值型營業稅法第 37 條第 1 項應行報繳營業稅之期限屆滿 前離境者，其營業稅，應於離境前報繳", "營業人除另有法律規定外，不論有無銷售額，應以每二月為一期，於次期開始15日內，填具規 定格式之申報書，檢附退抵稅款及其他有關文件，向主管稽徵機關申報銷售額、應納或溢付營 業稅額", "依加值型及非加值型營業稅法第23條規定「查定」計算營業稅額之營業人，由主管稽徵機關查 定其銷售額及稅額，每二個月填發繳款書通知繳納一次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00067', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '關於營業稅，下列敘述何者錯誤？', '["金片、金幣及純金之金飾或飾金之加工費，免徵營業稅", "銷售與保稅區營業人供營運之貨物，營業稅稅率為零", "依法取得從事按摩資格之視覺功能障礙者經營，且全部由視覺功能障礙者提供按摩勞務之按摩 業，其營業稅稅率為百分之一", "有陪侍服務之酒吧之營業稅稅率為百分之二十五"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00068', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列敘述何者錯誤？', '["進口本國之古物免徵營業稅", "受託人因公益信託而標售或義賣之貨物與舉辦之義演，其收入除支付標售、義賣及義演之必要 費用外，全部供作該公益事業之用者，免徵營業稅", "保險業人壽保險之退保收回之責任準備金，免徵營業稅", "診所提供之醫療勞務，免徵營業稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00069', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依我國目前「地價稅」相關法律規定，下列何者錯誤？', '["土地稅法所稱自用住宅用地，指土地所有權人或其配偶、直系親屬於該地辦竣戶籍登記，且無 出租或供營業用之住宅用地", "建造房屋應保留之法定空地，無償供公眾作為道路通行，經查明屬實者，在使用期間內免徵地 價稅", "土地所有權人之地價總額未超過土地所在地直轄市或縣（市）累進起點地價者，其地價稅按基 本稅率徵收，地價稅基本稅率為千分之十", "都市土地面積未超過三公畝部分之自用住宅用地，其地價稅按千分之二計徵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00070', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '關於營業稅之稅額計算，下列敘述何者錯誤？', '["營業人銷售貨物或勞務，除另有規定外，均應就「銷售額」，分別按加值型及非加值型營業稅法 第7條或第10條規定計算其銷項稅額", "「銷售額」，為營業人銷售貨物或勞務所收取之全部代價，包括營業人在貨物或勞務之價額外收 取之一切費用", "「銷售額」，包括本次銷售之營業稅額", "如係應徵貨物稅、菸酒稅或菸品健康福利捐之貨物，其「銷售額」應加計貨物稅額、菸酒稅額 或菸品健康福利捐金額在內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00071', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依遺產及贈與稅法規定，下列何者應計入遺產總額？', '["被繼承人擁有由其配偶創作之發明專利權", "約定於被繼承人死亡時，給付其所指定受益人之人壽保險金額", "繼承人捐贈全部公股之公營事業之財產", "被繼承人之債權不能收取或行使，確有證明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
